# act_inact_trial.R
# Purpose: Analysis/processing script for behavioral workflow data.
# Note: Public portfolio version; paths and sensitive identifiers should be parameterized. wd = "C:/Users/PC/Desktop/alex/rawdata/"
funcpath ="C:/Users/PC/Desktop/alex/"
experiment = "fr"
full_data_csvname = "act_inact_trial.csv"
binl=600 bins=seq(0,3600,binl)
setwd(wd) if (file.exists("./rdata")) {unlink("./rdata", recursive = TRUE)} # source(paste(funcpath,"master_script.R",sep=""),local=TRUE) # experiment_selection(wd) # fr_summary.rFUNC = function(wd,funcpath)({ # FR PART 1 ---- setwd(wd) files=list.files(wd) # csvname = "FR_data.csv" if (file.exists("./rdata")) {unlink("./rdata", recursive = TRUE)} dir.create(paste(wd,"rdata",sep="/")) savepath = funcpath rdat = "./rdata/" pointer=list() ## Beginning of For loop: Test by typing q=1 in R console for (q in (1:length(files))) ({ current=paste (wd,files[q],sep="") dat=scan (file=current,what="raw",skip=1) dat=c(dat,"Start") dat <- dat[-grep("MSN:", dat)] # ACTIVE PRESSES # Grabbing G: array, which contains absolute times of active(e.g. correct) lever presses active=apply(data.frame(grep("M:",dat)+1,grep("N:",dat)-1),1,function(x) (dat[x[1]:x[2]])) # Removing the 0:, 5:, 10:, ... active=lapply(active,function(x) (x[-grep(":",x)] )) # Determining the number of rats who didn't press the active lever at all noactive= unlist (lapply(active,function(x) (length(x)))) if (length (which(noactive==0)>0)) ({ noactidx=which(noactive==0)}) else ({ noactidx=NA }) # Creating columns labelled "abs.time" and "type" and filled with NA. "tofill" is for the purpose of the next section tofill=lapply(as.list(seq(1,length(active))),function(x) (as.data.frame (cbind (etime=NA,etype=NA)))) # Creating and filling "abs.time" column with data from "active" list and "type" column with "active" active=lapply(active,function(x) (data.frame (cbind(etime=as.numeric (x),etype="act"),stringsAsFactors=F))) # In the scenario that there are rats who DID NOT press the active lever at all, then this if-else statement fills that rat's abs.time and lever.type with NA from "tofill" which was created above. if (is.na (match(NA,noactidx))) ({ aidx=seq(1,length(active))[-noactidx] tofill[aidx]=active[aidx] active=tofill}) else({ active=active }) # Total count of correct responses for each rat -AL total.active= as.integer(apply(data.frame(grep("B:",dat)+3, grep("C:",dat)-7),1,function(x) (dat[x[1]:x[2]]))) # Latency to first active -AL firstA=sapply( X = active, FUN = function(X)( X$etime[1])) ## UNCOMMENT THE FOLLOWING WHEN MSN: "FR_SCRIPT" # # Grabbing H: array, which contains absolute times of inactive(e.g. incorrect) lever presses inactive=apply (data.frame (grep("N:",dat)+1,grep("O:",dat)-1),1,function(x) (dat[x[1]:x[2]])) # Removing the 0:, 5:, 10:, ... inactive=lapply(inactive,function(x) (x[-grep(":",x)] )) # Determining the number of rats who didn't press the inactive lever at all noinact= unlist (lapply(inactive,function(x) (length(x)))) if (length (which(noinact==0)>0)) ({ noinactidx=which(noinact==0)}) else ({ noinactidx=NA }) # Creating columns labelled "abs.time" and "type" and filled with NA. "tofill" is for the purpose of the next section tofill=lapply(as.list(seq(1,length(inactive))),function(x) (as.data.frame (cbind (etime=NA,etype=NA)))) # Creating and filling "abs.time" column with data from "inactive" list and "type" column with "inactive" inactive=lapply(inactive,function(x) (data.frame (cbind(etime=as.numeric (x),etype="inact"),stringsAsFactors=F))) # In the scenario that there are rats who DID NOT press the inactive lever at all, then this if-else statement fills that rat's abs.time and lever.type with NA from "tofill" which was created above. if (is.na (match(NA,noinactidx))) ({ inaidx=seq(1,length(inactive))[-noinactidx] tofill[inaidx]=inactive[inaidx] inactive=tofill}) else({ inactive=inactive }) # Total count of incorrect responses for each rat -AL total.inactive= as.integer(apply(data.frame(grep("B:",dat)+4, grep("C:",dat)-6),1,function(x) (dat[x[1]:x[2]]))) # Latency to first inactive -AL firstI=sapply( X = inactive, FUN = function(X)( X$etime[1])) # REWARD DELIVERY # the pip array is incomplete in this schedule so we will assume reward is delivered at the correct press time rewT=apply (data.frame (grep("M:",dat)+1,grep("N:",dat)-1),1,function(x) (dat[x[1]:x[2]])) rewT=lapply(rewT,function(x) (x[-grep(":",x)] )) rewT=lapply(rewT,function(x) (data.frame (cbind(etime=as.numeric (x),etype="rew"),stringsAsFactors=F))) reward=rewT tofill=lapply(as.list(seq(1,length(active))),function(x) (as.data.frame (cbind (etime=NA,etype=NA)))) if (is.na (match(NA,noactidx))) ({ aidx=seq(1,length(active))[-noactidx] tofill[aidx]=reward[aidx] reward=tofill}) else({ reward=reward }) timeout=as.numeric (dat[(grep("A:",dat)+5)])*0.01 fr=as.numeric(dat[(grep("A:",dat)+8)]) bindidx=as.list(seq(1,length(active))) datbind=lapply(bindidx,function(x) (data.frame (rbind(active[[x]],inactive[[x]],reward[[x]]),check.names=T,stringsAsFactors=F))) #we use bindidx to index and bind together all the data from a missingvals=lapply(datbind,function(x) (which(is.na (x$etime==T)))) datbind=lapply(datbind,function(x) (x[order(as.numeric (x$etime)),])) #here we order the combined data by time. #newdat=lapply(datbind,function(x) (x[-which(x$etime=="0"),])) #here we get rid of the zero time stamps to make the data tidy icidx=lapply(datbind,function(x) (which (complete.cases(x)==F))) mv=which (unlist (lapply (icidx,FUN=length))>0) nodatacheck=unlist (lapply(as.list (mv),function(x) (nrow(datbind[[x]])))) lengthidx=unlist (lapply(icidx[mv],function(x) (length(x) ))) nodatacheck=which (lengthidx==nodatacheck) if (length(nodatacheck)>0) ({ mv=mv[-nodatacheck] }) naidx=icidx[mv] if (length(naidx)>0) ({ repidx=datbind[mv] iidx=as.list (seq(1,length(repidx))) trimmed=lapply(iidx,function(x) (repidx[[x]][-naidx[[x]],])) datbind[mv]=trimmed }) total.reward=apply (data.frame(grep("F:", dat)+1,grep("I:", dat)-1),1,function(x) (dat[x[1]:x[2]])) total.reward=as.integer(total.reward) # Creating index values in order to grab Comments #comidx=grep("Comments:",dat) #Index value of each "Comments:" #sidx=c(grep ("Start",dat),length(dat)) #Index value of "Start" #comend=unlist (lapply(as.list (comidx),function (x) (which ((x-sidx)<0))[1])) #comments=apply(data.frame (comidx+1,sidx[comend]-1),1,function(x) (dat[x[2]])) # CREATING FILES AND CONSOLIDATING INTO 1 POINTER FILE dates=gsub ("/","-",dat[grep("Subject",dat)-4]) # here we get the subject information from the headers subject=paste(dat[grep("Subject:", dat)+1], sep="") #subject number - AL group=paste (dat[grep("Group:",dat)+1],sep="_") #group - AL boxnum=paste ("Box",dat[grep("Box:",dat)+1],sep="") #boxnumber #weight=paste (dat[grep("A:",dat)+14],sep="") #weight #boxnum=unlist (lapply (strsplit (paste ("Box",dat[grep("Box:",dat)+1],sep=""),"Box"),function(x) (x[2]))) etype=apply (data.frame (cbind(grep("Experiment:",dat)+1,grep("Group:",dat)-1)),1,function(x) (paste (dat[seq (x[1],x[2])],collapse="_"))) #experiment type # msn=apply (data.frame (cbind(grep("MSN:",dat)+1,grep("A:",dat)-1)),1,function(x) (paste (dat[seq (x[1],x[2])],collapse="_"))) #schedule name outnames=seq(1,length(datbind)) #this is for the situation I described where there may be files that do not contain "bad" names pointer[[q]]=data.frame(id=outnames, subject=subject, etype=etype, group=group,edate=dates, boxnum=boxnum,iti=timeout,fr=fr,fn=files[q]) filenames=paste (paste(pointer[[q]]$fn,pointer[[q]]$id,sep="_"),".rDat",sep="") pointer[[q]]$sname=filenames #add these file names to pointer so we can readily associate a file name with a specific rat, day and experiment type. pointer[[q]]$active=total.active #added by AL pointer[[q]]$inactive=total.inactive #added by AL pointer[[q]]$reward=total.reward #added by AL # pointer[[q]]$weight=weight #added by AL pointer[[q]]$latency.active=firstA pointer[[q]]$latency.inactive=firstI # if (length(comments) > 0) {pointer[[q]]$comments=comments} #this is a custom function to save the data which I apply below. The input is x=newdat[[p]],y=savedir,z=filenames[[p]] save.rFunc=function(x,y,z) ({ save(x,file=paste(y,z,sep="")) return() }) applysave=sapply(seq(1,length(datbind)),function(p) (save.rFunc(datbind[[p]],rdat,filenames[[p]]))) #here I save all the files to your savedir that #you name at the top of the script. #here we save the pointer }) pointer=do.call("rbind",pointer) save(pointer,file=paste(rdat,"pointer.rDAT",sep="")) write.csv(pointer,file=paste(rdat,"pointer_csv.csv",sep="")) # FR PART 2 ---- files=list.files(rdat) load (paste(rdat,"pointer.rDAT",sep="")) #uploading the pointer file full_data_csvname = full_data_csvname datout=data.frame() # Beginning of for loop: x is the rat's data containing abs.time of inactive, active, and reward for (q in (1:nrow(pointer))) ({ current=match(pointer$sname[q],files) load(paste(rdat,files[current],sep="")) ints=findInterval(x$etime,bins) x$int=ints uidx=seq(1,length (unique(bins))-1) # ap= binned active presses, ip=binned inactive presses ap=sapply(uidx,function(p) (length(which(x$int==p & x$etype=="act")))) ip=sapply(uidx,function(p) (length(which(x$int==p & x$etype=="inact")))) rewidx=which(x$etype=="rew") itiend=c(0,as.numeric (x$etime[rewidx]) + pointer$iti[q]) #finding when timeout period ends itiend=itiend[-length(itiend)] atimes=as.numeric (x$etime[which(x$etype=="act")]) #the times at which the active lever was pressed rew=ap fr=pointer$fr[q] firstA=x$etime[which(x$etype=="act")][1] firstI=x$etime[which(x$etype=="inact")][1] nidx=seq (1,length(bins)) binn=sapply(nidx,function(p) (paste(bins[nidx[p]],bins[nidx[p+1]],sep="-"))) #bin size binn=binn[-length(binn)] #Creating bins for each variable of interest (e.g. active, inactive, reward, etc.) an=paste("act",binn,sep="") iAn=paste("inact",binn,sep="") rn=paste("rew",binn,sep="") fla="latency to first active" fli="latency to first inactive" #This is where certain columns from pointer are preserved and filled into a new object called "tofill.final" Add identifiers here -AL tofill.final=c(as.character(pointer$subject[q]), as.character(pointer$etype[q]), as.character(pointer$group[q]), as.character(pointer$boxnum[q]), as.vector(pointer$edate[q]), # as.numeric(pointer$weight[q]), pointer$fn[q], pointer$fr[q], as.numeric(pointer$active[q]), as.numeric(pointer$inactive[q]), as.numeric(pointer$reward[q]), round (as.numeric (firstA),digits=2), round (as.numeric (firstI),digits=2), ap, ip, rew, as.character(pointer$comments[q])) tofill.final=data.frame (rbind(tofill.final)) outnames=c("subject","e.type","group","boxnum","edate","file name", "fr", "active", "inactive", "reward", fla,fli,an,iAn,rn) colnames(tofill.final)=outnames datout=rbind(datout,tofill.final) }) write.csv(datout,file=paste(funcpath,full_data_csvname,sep=""), row.names=F) # }) setwd(funcpath) dat <- read.csv(full_data_csvname) sub_dat <- dat[, 13:length(dat)] result <- sapply(split.default(sub_dat, substr(names(sub_dat), 1, 3)), rowSums) dat[, c('active', 'inactive', 'reward')] <- result write.csv(dat,file=paste(funcpath,full_data_csvname,sep=""), row.names=F) 